MAX_HOPS = 5

def safe_multihop(question: str, vectorstore, k: int = 3) -> str:
    plan = planner.invoke({"question": question})
    if len(plan.sub_questions) > MAX_HOPS:
        # Truncate rather than let a runaway plan consume budget
        plan.sub_questions = plan.sub_questions[:MAX_HOPS]

    prior: dict[str, str] = {}
    for i, sub_q in enumerate(plan.sub_questions, start=1):
        filled_q = sub_q
        for key, val in prior.items():
            filled_q = filled_q.replace(f"{{{{{key}}}}}", val)

        docs = vectorstore.similarity_search(filled_q, k=k)
        if not docs:
            prior[f"answer_{i}"] = "[no relevant documents found]"
            continue

        context = "\n".join(d.page_content for d in docs)
        ans = answerer.invoke({"context": context, "sub_question": filled_q})

        # Confidence check: if answer looks like a refusal, note it
        if any(phrase in ans.lower() for phrase in
               ["i don't know", "i cannot", "not mentioned", "not found"]):
            prior[f"answer_{i}"] = f"[uncertain: {ans[:100]}]"
        else:
            prior[f"answer_{i}"] = ans

    synth_prompt = ChatPromptTemplate.from_messages([
        ("system",
         "Answer the original question using the intermediate answers. "
         "If any answer is uncertain, note that in the final answer."),
        ("human", "Original: {q}\nAnswers: {a}"),
    ])
    answers_text = "\n".join(f"{k}: {v}" for k, v in prior.items())
    return (synth_prompt | llm | StrOutputParser()).invoke({
        "q": question, "a": answers_text
    })

from dataclasses import dataclass, field

@dataclass
class MultihopEvalResult:
    question:         str
    predicted_answer: str
    gold_answer:      str
    gold_intermediate: list[str]   # expected intermediate facts
    hops_taken:       int
    hop_answers:      list[str]    # actual intermediate answers

    @property
    def intermediate_f1(self) -> float:
        """What fraction of gold intermediate facts appeared in hop answers?"""
        if not self.gold_intermediate:
            return 1.0
        all_hop_text = " ".join(self.hop_answers).lower()
        found = sum(
            1 for fact in self.gold_intermediate
            if fact.lower() in all_hop_text
        )
        return found / len(self.gold_intermediate)

    @property
    def over_hopped(self) -> bool:
        """Did the pipeline use more hops than necessary?"""
        return self.hops_taken > len(self.gold_intermediate)

def evaluate_multihop_dataset(results: list[MultihopEvalResult]) -> dict:
    em    = sum(
        1 for r in results
        if r.predicted_answer.strip().lower() == r.gold_answer.strip().lower()
    ) / len(results)
    int_f1 = sum(r.intermediate_f1 for r in results) / len(results)
    over   = sum(1 for r in results if r.over_hopped) / len(results)
    avg_h  = sum(r.hops_taken for r in results) / len(results)

    print(f"Exact match (final answer):  {em:.3f}")
    print(f"Intermediate fact coverage:  {int_f1:.3f}")
    print(f"Over-hopping rate:           {over:.1%}")
    print(f"Average hops per question:   {avg_h:.1f}")
    return {"em": em, "intermediate_f1": int_f1, "over_hop_rate": over}
